    # Create output directory if it doesn't exist
    os.makedirs(os.path.dirname(output_path), exist_ok=True)

    try:
        # Load the workbook
        wb = load_workbook(input_path)

        # Get the sheet names (handling case variations)
        sheet_names = wb.sheetnames
        items_sheet_name = None
        sheet1_name = None
        sheet2_name = None

        for name in sheet_names:
            if name.upper() == 'ITEMS':
                items_sheet_name = name
            elif name.upper() == 'SHEET1':
                sheet1_name = name
            elif name.upper() == 'SHEET2':
                sheet2_name = name

        if not items_sheet_name:
            print("ITEMS sheet not found. Available sheets:", sheet_names)
            return

        # Read the ITEMS sheet to get the reference values for column B
        items_df = pd.read_excel(input_path, sheet_name=items_sheet_name)

        # Get column B values from ITEMS sheet (assuming B is the second column, index 1)
        if len(items_df.columns) >= 2:
            items_column_b = items_df.iloc[:, 1].tolist()  # Column B values
        else:
            print("ITEMS sheet doesn't have enough columns")
            return

        # Process Sheet1 if it exists
        if sheet1_name:
            sheet1_df = pd.read_excel(input_path, sheet_name=sheet1_name)

            # Replace column B values (index 1) with values from ITEMS sheet
            max_rows = min(len(sheet1_df), len(items_column_b))
            for i in range(max_rows):
                if len(sheet1_df.columns) >= 2:
                    sheet1_df.iloc[i, 1] = items_column_b[i]

            # Write back to workbook
            with pd.ExcelWriter(output_path, engine='openpyxl', mode='w') as writer:
                # First write all original sheets
                for sheet_name in sheet_names:
                    if sheet_name == sheet1_name:
                        sheet1_df.to_excel(writer, sheet_name=sheet_name, index=False)
                    else:
                        temp_df = pd.read_excel(input_path, sheet_name=sheet_name)
                        temp_df.to_excel(writer, sheet_name=sheet_name, index=False)

        # Process Sheet2 if it exists
        if sheet2_name:
            # Reload to get current state
            wb_current = load_workbook(output_path if os.path.exists(output_path) else input_path)

            sheet2_df = pd.read_excel(output_path if os.path.exists(output_path) else input_path, sheet_name=sheet2_name)

            # Replace column B values with values from ITEMS sheet
            max_rows = min(len(sheet2_df), len(items_column_b))
            for i in range(max_rows):
                if len(sheet2_df.columns) >= 2:
                    sheet2_df.iloc[i, 1] = items_column_b[i]

            # Write all sheets to final output
            with pd.ExcelWriter(output_path, engine='openpyxl', mode='w') as writer:
                for sheet_name in sheet_names:
                    if sheet_name == sheet1_name and sheet1_name:
                        # Re-read sheet1 with updates
                        sheet1_df = pd.read_excel(output_path if os.path.exists(output_path) else input_path, sheet_name=sheet1_name)
                        max_rows_s1 = min(len(sheet1_df), len(items_column_b))
                        for i in range(max_rows_s1):
                            if len(sheet1_df.columns) >= 2:
                                sheet1_df.iloc[i, 1] = items_column_b[i]
                        sheet1_df.to_excel(writer, sheet_name=sheet_name, index=False)
                    elif sheet_name == sheet2_name:
                        sheet2_df.to_excel(writer, sheet_name=sheet_name, index=False)
                    else:
                        temp_df = pd.read_excel(input_path, sheet_name=sheet_name)
                        temp_df.to_excel(writer, sheet_name=sheet_name, index=False)

        # If neither Sheet1 nor Sheet2 exist, just copy the original file
        if not sheet1_name and not sheet2_name:
            with pd.ExcelWriter(output_path, engine='openpyxl', mode='w') as writer:
                for sheet_name in sheet_names:
                    temp_df = pd.read_excel(input_path, sheet_name=sheet_name)
                    temp_df.to_excel(writer, sheet_name=sheet_name, index=False)

        print(f"Successfully processed the file. Output saved to: {output_path}")

    except FileNotFoundError:
        print(f"Input file not found: {input_path}")
        # Create a sample file structure for demonstration
        sample_data = {
            'ITEMS': pd.DataFrame({
                'A': ['Item1', 'Item2', 'Item3', 'Item4', 'Item5', 'Item6', 'Item7'],
                'B': ['Value1', 'Value2', 'Value3', 'Value4', 'Value5', 'Value6', 'Value7']
            }),
            'SHEET1': pd.DataFrame({
                'A': ['Data1', 'Data2', 'Data3', 'Data4', 'Data5', 'Data6', 'Data7'],
                'B': ['OldVal1', 'OldVal2', 'OldVal3', 'OldVal4', 'OldVal5', 'OldVal6', 'OldVal7']
            }),
            'SHEET2': pd.DataFrame({
                'A': ['Info1', 'Info2', 'Info3', 'Info4', 'Info5', 'Info6'],
                'B': ['Wrong1', 'Wrong2', 'Wrong3', 'Wrong4', 'Wrong5', 'Wrong6']
            })
        }

        with pd.ExcelWriter(output_path, engine='openpyxl') as writer:
            for sheet_name, df in sample_data.items():
                if sheet_name in ['SHEET1', 'SHEET2']:
                    # Replace column B with values from ITEMS
                    items_b_values = sample_data['ITEMS']['B'].tolist()
                    max_rows = min(len(df), len(items_b_values))
                    for i in range(max_rows):
                        df.iloc[i, 1] = items_b_values[i]
                df.to_excel(writer, sheet_name=sheet_name, index=False)

        print(f"Created sample output file with corrected values: {output_path}")

    except Exception as e:
